UPDATE public.questions SET
  stimulus_text = 'A new study has been published in the journal *Nature* that claims that the use of social media is linked to a decline in mental well-being. The study tracked the amount of time that a sample of 500 people spent using social media each day and correlated that data to their levels of anxiety and depression. The researchers found that people who spent more than two hours a day using social media had a higher likelihood of reporting anxiety and depression symptoms compared to those who spent less than two hours a day on social media.',
  question_text = 'Which of the following is a likely criticism of this study?',
  stimulus_type = NULL,
